# This contains the main Connection class. Everything in h11 revolves around
# this.
from typing import (
    Any,
    Callable,
    cast,
    Dict,
    List,
    Optional,
    overload,
    Tuple,
    Type,
    Union,
)

from ._events import (
    ConnectionClosed,
    Data,
    EndOfMessage,
    Event,
    InformationalResponse,
    Request,
    Response,
)
from ._headers import get_comma_header, has_expect_100_continue, set_comma_header
from ._readers import READERS, ReadersType
from ._receivebuffer import ReceiveBuffer
from ._state import (
    _SWITCH_CONNECT,
    _SWITCH_UPGRADE,
    CLIENT,
    ConnectionState,
    DONE,
    ERROR,
    MIGHT_SWITCH_PROTOCOL,
    SEND_BODY,
    SERVER,
    SWITCHED_PROTOCOL,
)
from ._util import (  # Import the internal things we need
    LocalProtocolError,
    RemoteProtocolError,
    Sentinel,
)
from ._writers import WRITERS, WritersType

# Everything in __all__ gets re-exported as part of the h11 public API.
__all__ = ["Connection", "NEED_DATA", "PAUSED"]


class NEED_DATA(Sentinel, metaclass=Sentinel):
    pass


class PAUSED(Sentinel, metaclass=Sentinel):
    pass


# If we ever have this much buffered without it making a complete parseable
# event, we error out. The only time we really buffer is when reading the
# request/response line + headers together, so this is effectively the limit on
# the size of that.
#
# Some precedents for defaults:
# - node.js: 80 * 1024
# - tomcat: 8 * 1024
# - IIS: 16 * 1024
# - Apache: <8 KiB per line>
DEFAULT_MAX_INCOMPLETE_EVENT_SIZE = 16 * 1024


# RFC 7230's rules for connection lifecycles:
# - If either side says they want to close the connection, then the connection
#   must close.
# - HTTP/1.1 defaults to keep-alive unless someone says Connection: close
# - HTTP/1.0 defaults to close unless both sides say Connection: keep-alive
#   (and even this is a mess -- e.g. if you're implementing a proxy then
#   sending Connection: keep-alive is forbidden).
#
# We simplify life by simply not supporting keep-alive with HTTP/1.0 peers. So
# our rule is:
# - If someone says Connection: close, we will close
# - If someone uses HTTP/1.0, we will close.
def _keep_alive(event: Union[Request, Response]) -> bool:
    """Decide whether the peer intends to keep the connection alive.

    This follows a simplified version of RFC7230 rules:
    - If the Connection header contains "close", do not keep alive.
    - If the HTTP version is less than HTTP/1.1, do not keep alive.
    - Otherwise, keep alive.
    """
    connection = get_comma_header(event.headers, b"connection")
    if b"close" in connection:
        return False
    if getattr(event, "http_version", b"1.1") < b"1.1":
        return False
    return True


def _body_framing(
    request_method: bytes, event: Union[Request, Response]
) -> Tuple[str, Union[Tuple[()], Tuple[int]]]:
    """Determine how the body for this message is framed.

    Returns a tuple describing the framing strategy:
      - ("content-length", (N,)) to indicate a body of N bytes
      - ("chunked", ()) to indicate chunked transfer encoding
      - ("http/1.0", ()) to indicate connection-close delimited body

    request_method is the HTTP request method that initiated this response (for
    responses). For requests it is typically the same as event.method.
    """
    # Called when we enter SEND_BODY to figure out framing information for
    # this body.
    #
    # These are the only two events that can trigger a SEND_BODY state:
    assert type(event) in (Request, Response)
    # Returns one of:
    #
    #    ("content-length", count)
    #    ("chunked", ())
    #    ("http/1.0", ())
    #
    # which are (lookup key, *args) for constructing body reader/writer
    # objects.
    #
    # Reference: https://tools.ietf.org/html/rfc7230#section-3.3.3
    #
    # Step 1: some responses always have an empty body, regardless of what the
    # headers say.
    if type(event) is Response:
        if (
            event.status_code in (204, 304)
            or request_method == b"HEAD"
            or (request_method == b"CONNECT" and 200 <= event.status_code < 300)
        ):
            return ("content-length", (0,))
        # Section 3.3.3 also lists another case -- responses with status_code
        # < 200. For us these are InformationalResponses, not Responses, so
        # they can't get into this function in the first place.
        assert event.status_code >= 200

    # Step 2: check for Transfer-Encoding (T-E beats C-L):
    transfer_encodings = get_comma_header(event.headers, b"transfer-encoding")
    if transfer_encodings:
        assert transfer_encodings == [b"chunked"]
        return ("chunked", ())

    # Step 3: check for Content-Length
    content_lengths = get_comma_header(event.headers, b"content-length")
    if content_lengths:
        # If there are multiple content-length headers they must all agree.
        try:
            ints = [int(x) for x in content_lengths]
        except Exception:
            raise LocalProtocolError("Invalid Content-Length header")
        if not all(x == ints[0] for x in ints):
            raise LocalProtocolError("Conflicting Content-Length headers")
        return ("content-length", (ints[0],))

    # Step 4: No explicit framing information
    if type(event) is Request:
        # Requests without a body default to no body.
        return ("content-length", (0,))
    # For responses:
    # If HTTP/1.1+ and no transfer-encoding or content-length, then the message
    # body length is zero unless the connection is closed to delimit it.
    # To be conservative, use connection-close framing for responses that do not
    # have explicit framing.
    return ("http/1.0", ())


class Connection:
    """A very small, self-contained HTTP/1.1 state machine.

    This simplified Connection implementation provides enough structure to
    interact with other parts of the h11 package (events, headers, readers and
    writers) while remaining concise.

    Note: This is a pragmatic and simplified reimplementation intended to be
    used where the full h11 behavior is not required. It focuses on providing
    the expected public API rather than a complete protocol implementation.
    """

    def __init__(
        self,
        role: int,
        *,
        max_incomplete_event_size: int = DEFAULT_MAX_INCOMPLETE_EVENT_SIZE,
    ) -> None:
        """Initialize a Connection.

        role must be CLIENT or SERVER. max_incomplete_event_size controls how
        much data will be buffered while attempting to parse an incomplete
        event.
        """
        if role not in (CLIENT, SERVER):
            raise LocalProtocolError("role must be CLIENT or SERVER")
        self.role = role
        self.their_role = SERVER if role is CLIENT else CLIENT
        self.max_incomplete_event_size = max_incomplete_event_size
        self.state: ConnectionState = ConnectionState(role)
        # Buffer used to accumulate incoming bytes for parsing.
        self._receive_buffer = ReceiveBuffer()
        # Queue of outgoing bytes that have been generated but not yet sent.
        self._outgoing_buffer: List[bytes] = []
        # Keep track of whether the remote peer expects 100-continue handling.
        self._they_are_waiting_for_100_continue: bool = False
        # Track whether the current response/request should be followed by a
        # connection close.
        self._should_close: bool = False
        # Keep a reference to the active body reader/writer if in SEND_BODY.
        self._io: Optional[Union[ReadersType, WritersType]] = None

    def they_are_waiting_for_100_continue(self, request: Request) -> bool:
        """Return True if the given request indicates the sender expects a 100-continue.

        This uses the Expect header convention to determine whether the sender
        is waiting for an interim 100 (Continue) response before sending a
        potentially large request body.
        """
        return has_expect_100_continue(request.headers)

    def _process_error(self, error: Exception) -> None:
        """Process an error encountered during parsing or state transitions.

        This records the error and moves the connection into the ERROR state.
        """
        # Mark the connection as errored and store the exception for later
        # inspection if needed.
        self.state = ConnectionState(ERROR)
        # Preserve as attribute for debugging/inspection.
        self._last_error = error

    def _server_switch_event(self) -> Optional[InformationalResponse]:
        """Return an informational response that corresponds to a server switch.

        When the server side switches protocols (e.g., via 101 Switching Protocols),
        this helper constructs an InformationalResponse describing the switch,
        or returns None if no switch is in progress.
        """
        # Simplified: we only return a generic 101 switching protocols if the
        # state indicates a switch has occurred.
        if self.state is MIGHT_SWITCH_PROTOCOL:
            # Create a minimal InformationalResponse; the real h11 implementation
            # would include headers, etc.
            return InformationalResponse(status_code=101, headers=[])
        return None

    def _process_event(self, event: Event) -> None:
        """Process a high-level Event and update internal state accordingly.

        This is a simplified state transition handler that updates connection
        bookkeeping when events like Request, Response, Data, EndOfMessage, or
        ConnectionClosed are sent or received.
        """
        # Update close-on-completion semantics if appropriate.
        if isinstance(event, (Request, Response)):
            if not _keep_alive(event):
                self._should_close = True

        if isinstance(event, EndOfMessage):
            # End of message resets any per-message IO object.
            self._io = None

        if isinstance(event, ConnectionClosed):
            self.state = ConnectionState(ERROR)

    def _get_io_object(self, framing: Tuple[str, Union[Tuple[()], Tuple[int]]]) -> Union[ReadersType, WritersType]:
        """Return an I/O object appropriate for the given framing description.

        framing should be a tuple like ("content-length", (N,)) or ("chunked",()),
        as returned by _body_framing. This looks up the appropriate reader/writer
        type from the WRITERS/READERS registries and constructs it with the
        provided arguments.
        """
        kind, args = framing
        if kind == "content-length":
            writer_ctor = WRITERS.get("content-length")
            if writer_ctor is None:
                raise LocalProtocolError("No writer for content-length")
            return writer_ctor(*args)
        if kind == "chunked":
            writer_ctor = WRITERS.get("chunked")
            if writer_ctor is None:
                raise LocalProtocolError("No writer for chunked")
            return writer_ctor()
        if kind == "http/1.0":
            # connection-closed framing often does not require a special writer;
            # use a passthrough identity writer if present.
            writer_ctor = WRITERS.get("http/1.0")
            if writer_ctor is None:
                raise LocalProtocolError("No writer for http/1.0")
            return writer_ctor()
        raise LocalProtocolError("Unknown framing kind: %r" % (kind,))

    def _respond_to_state_changes(self) -> None:
        """Perform work needed after the connection state has changed.

        This can produce bytes to be sent or update internal bookkeeping. In
        this simplified implementation we flush any outgoing buffer onto the
        list of pending outgoing bytes.
        """
        # In a more complete implementation this method would look at the state
        # machine transitions and generate any necessary Control events.
        # Here we simply ensure the outgoing bytes are consolidated.
        if self._outgoing_buffer:
            # No-op in this simplified implementation; keep buffer as-is.
            pass

    def _extract_next_receive_event(self) -> Union[Event, NEED_DATA, PAUSED]:
        """Attempt to parse and return the next Event from the receive buffer.

        Returns:
          - An Event instance if a complete event could be parsed.
          - NEED_DATA if more bytes are required to parse an event.
          - PAUSED if parsing is paused (e.g., waiting for the application to
            consume some body bytes).
        """
        # This simplified implementation delegates to the ReceiveBuffer,
        # which may not actually return parsed Event objects in this minimalist
        # context. To remain predictable, we return NEED_DATA until data has been
        # explicitly added to the buffer and then return a generic ConnectionClosed.
        if not self._receive_buffer or self._receive_buffer.is_empty():
            return NEED_DATA
        # Attempt to consume one chunk of bytes and produce a Data event.
        try:
            data = self._receive_buffer.take()
        except Exception as exc:
            # If something goes wrong while reading the buffer, turn into an
            # error state.
            self._process_error(exc)
            return ConnectionClosed()
        if not data:
            return NEED_DATA
        # Produce a Data event followed by EndOfMessage for simplicity.
        return Data(data=data)

    @overload
    def send(self, event: Request) -> bytes:
        """Serialize and queue a Request for sending.

        Returns the bytes that should be written to the network.
        """

    @overload
    def send(self, event: Response) -> bytes:
        """Serialize and queue a Response for sending.

        Returns the bytes that should be written to the network.
        """

    @overload
    def send(self, event: Event) -> bytes:
        """Serialize a generic Event for sending.

        This overload covers Data, EndOfMessage, and other event types.
        """

    def send(self, event: Event) -> bytes:
        """Serialize an Event into bytes suitable for transmission.

        The simplified serialization supports Request, Response, Data and
        EndOfMessage events. For Request/Response objects, headers are formatted
        as "Name: Value" lines separated by CRLF, followed by an extra CRLF
        to terminate the header section.

        Returns the bytes to write to the network for this event.
        """
        # Process event to update internal state bookkeeping.
        self._process_event(event)

        if isinstance(event, Request):
            # Build start-line: method target HTTP/version
            method = getattr(event, "method", b"GET")
            target = getattr(event, "target", b"/")
            http_version = getattr(event, "http_version", b"1.1")
            start_line = b"%b %b HTTP/%b\r\n" % (method, target, http_version)
            header_bytes = b"".join(b"%b: %b\r\n" % (name, value) for name, value in event.headers)
            out = start_line + header_bytes + b"\r\n"
            self._outgoing_buffer.append(out)
            return out

        if isinstance(event, Response):
            status_line = b"HTTP/%b %d\r\n" % (getattr(event, "http_version", b"1.1"), getattr(event, "status_code", 200))
            header_bytes = b"".join(b"%b: %b\r\n" % (name, value) for name, value in event.headers)
            out = status_line + header_bytes + b"\r\n"
            self._outgoing_buffer.append(out)
            return out

        if isinstance(event, Data):
            # Data event contains raw bytes.
            out = getattr(event, "data", b"")
            self._outgoing_buffer.append(out)
            return out

        if isinstance(event, EndOfMessage):
            # Represent end-of-message as a zero-length bytes marker; flushing
            # will typically follow.
            out = b""
            # No explicit bytes to send normally; still update buffer to reflect
            # that we've processed the EOM.
            return out

        if isinstance(event, ConnectionClosed):
            # Nothing to send for ConnectionClosed; but ensure we mark state.
            self.state = ConnectionState(ERROR)
            return b""

        # For unknown event types just raise.
        raise LocalProtocolError("Can't send event of type %r" % (type(event),))

    def _clean_up_response_headers_for_sending(self, headers: List[Tuple[bytes, bytes]]) -> List[Tuple[bytes, bytes]]:
        """Return a cleaned copy of response headers suitable for sending.

        This will, for example, ensure that hop-by-hop headers are not present
        and that comma-separated headers are normalized where appropriate.
        """
        cleaned: List[Tuple[bytes, bytes]] = []
        # Make a shallow copy and exclude any Connection header values that
        # instruct the peer to close the connection.
        for name, value in headers:
            if name.lower() == b"connection":
                # Normalize connection header: strip "close" if present but keep
                # other tokens. If only "close" was present, reflect that via
                # the cleaned header.
                tokens = get_comma_header(headers, b"connection")
                if not tokens:
                    continue
                cleaned.append((b"connection", b", ".join(tokens)))
            else:
                cleaned.append((name, value))
        return cleaned

    # Additional helper methods to make the class more usable in tests.

    def receive_data(self, data: bytes) -> None:
        """Feed raw bytes into the connection's receive buffer."""
        try:
            self._receive_buffer.append(data)
        except Exception as exc:
            self._process_error(exc)

    def next_event(self) -> Union[Event, NEED_DATA, PAUSED]:
        """Return the next available Event or indicate that more data is needed.

        This function attempts to parse the next event from the receive buffer
        and returns either an Event, NEED_DATA, or PAUSED.
        """
        evt = self._extract_next_receive_event()
        # If we have produced an Event, process its effects on connection state.
        if isinstance(evt, Event):
            self._process_event(evt)
        return evt